import React, { useEffect, useState } from 'react';
import { supabase } from './supabaseClient';
import {
  ComposedChart, Line, XAxis, YAxis, CartesianGrid, Tooltip, Legend, Area, ResponsiveContainer
} from 'recharts';

const CustomizedDot = (props) => {
  const { cx, cy, payload } = props;
  if (payload.discount === 0 || isNaN(payload.discount)) {
    return null;
  }
  return (
    <circle cx={cx} cy={cy} r={2} fill="#EA4335" stroke="none" />
  );
};

function DiscountChart({ 
  tableName, 
  title, 
  xAxisKey = 'Day', 
  yAxis1Key = 'Discount/Premium', 
  yAxis2Key = 'Backing Value',
  yAxisDomain = [0, 2.5]
}) {
  const [data, setData] = useState([]);

  useEffect(() => {
    const fetchData = async () => {
      const { data, error } = await supabase.from(tableName).select('*');
      if (error) {
        console.error('Error fetching data:', error);
      } else {
        const formattedData = data.map((item) => ({
          day: item[xAxisKey],
          discount: parseFloat(item[yAxis1Key]),
          backingValue: parseFloat(item[yAxis2Key]),
        }));

        const sortedData = formattedData.sort((a, b) => a.day - b.day);
        setData(sortedData);
      }
    };
    fetchData();
  }, [tableName, xAxisKey, yAxis1Key, yAxis2Key]);

  return (
    <div style={{ width: '100%', height: 500, margin: '20px' }}>
      <h2 style={{ textAlign: 'left', color: '#000', fontSize: '44px', marginBottom: '20px', marginLeft: '40px'}}>
        {title} <span style={{ backgroundColor: '#4285F4', color: 'white', borderRadius: '50%', padding: '2px 8px', marginLeft: '5px' }}>M</span>
      </h2>
      <ResponsiveContainer width="100%" height="100%">
        <ComposedChart data={data}>
          <CartesianGrid strokeDasharray="3 3" stroke="#ccc" />
          <XAxis dataKey="day" />
          <YAxis domain={yAxisDomain} ticks={[0, 0.5, 1, 1.5, 2, 2.5]}/>
          <Tooltip 
            contentStyle={{ backgroundColor: 'rgba(255, 255, 255, 0.8)', border: '1px solid #ccc', borderRadius: '10px'}}
            labelStyle={{ color: '#666' }}
            itemStyle={{ color: '#666' }}
          />
          <Legend />
          <defs>
            <linearGradient id="colorUv" x1="0" y1="0" x2="0" y2="1">
              <stop offset="5%" stopColor="#82ca9d" stopOpacity={0.2}/>
              <stop offset="95%" stopColor="#82ca9d" stopOpacity={0}/>
            </linearGradient>
          </defs>
          <Area type="monotone" dataKey="backingValue" stroke="#82ca9d" fillOpacity={1} fill="url(#colorUv)" />
          <Line type="monotone" dataKey="discount" name="Δ Discount/Premium in HEX" stroke="#EA4335" strokeWidth={2} dot={<CustomizedDot />} />
          <Line type="monotone" dataKey="backingValue" name="Backing Value" stroke="#82ca9d" strokeWidth={2} dot={false} />
        </ComposedChart>
      </ResponsiveContainer>
    </div>
  );
}

export default DiscountChart;
